<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { ElMessage, ElMessageBox } from 'element-plus'; import { commentsApi } from '../api'; import type { Comment } from '../types';
const comments = ref<Comment[]>([]); const loading = ref(false); async function load() { loading.value = true; try { comments.value = (await commentsApi.list()).data; } finally { loading.value = false; } } async function toggle(row: Comment) { await commentsApi.toggle(row._id, !row.visible); row.visible = !row.visible; ElMessage.success(row.visible ? '评论已展示' : '评论已隐藏'); } async function remove(row: Comment) { await ElMessageBox.confirm('确定删除这条评论？', '提示'); await commentsApi.remove(row._id); load(); } onMounted(load); const title = (post: Comment['postId']) => typeof post === 'string' ? post : post?.title || '未知文章'; const date = (d: string) => new Date(d).toLocaleString('zh-CN');
</script>
<template><div class="page-title"><div><h2>评论管理</h2><span class="muted">评论默认展示，可随时隐藏</span></div></div><el-card shadow="never"><el-table v-loading="loading" :data="comments"><el-table-column label="文章" min-width="170"><template #default="{ row }">{{ title(row.postId) }}</template></el-table-column><el-table-column prop="nickname" label="昵称" width="120" /><el-table-column prop="content" label="评论内容" min-width="280" show-overflow-tooltip /><el-table-column label="时间" width="170"><template #default="{ row }">{{ date(row.createdAt) }}</template></el-table-column><el-table-column label="状态" width="95"><template #default="{ row }"><el-tag :type="row.visible ? 'success' : 'info'">{{ row.visible ? '展示中' : '已隐藏' }}</el-tag></template></el-table-column><el-table-column label="操作" width="150"><template #default="{ row }"><el-button link type="primary" @click="toggle(row)">{{ row.visible ? '隐藏' : '展示' }}</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table></el-card></template>
